    return () => window.removeEventListener("keydown", onKeyDown);
  }, [editor]);

  // Cmd+Shift+V — paste as plain text, stripping all rich formatting
  useEffect(() => {
    function onKeyDown(e: KeyboardEvent) {
      if (!(e.metaKey || e.ctrlKey) || !e.shiftKey || e.key?.toLowerCase() !== "v") return;
      if (!editor?.isFocused) return;
      e.preventDefault();
      navigator.clipboard.readText().then((text) => {
        editor.chain().focus().insertContent(text).run();
      });
    }
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [editor]);

  // Cmd+H — open / close find & replace bar
  useEffect(() => {
    function onKeyDown(e: KeyboardEvent) {
      if (!(e.metaKey || e.ctrlKey) || e.key?.toLowerCase() !== "h") return;
      if (!editor?.isFocused && !showFindReplace) return;
      e.preventDefault();
      setShowFindReplace((v) => !v);
    }
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [editor, showFindReplace]);

  // Insert / Format menu commands forwarded from the native menu bar
  useEffect(() => {
    let mounted = true;
    let unlisten: (() => void) | undefined;
    listen<string>("menu-action", (event) => {
      if (!editor || linkDialog) return;
      switch (event.payload) {
        case "format-bold":
          editor.chain().focus().toggleBold().run();
          break;
        case "format-italic":
          editor.chain().focus().toggleItalic().run();
          break;
        case "format-strike":
          editor.chain().focus().toggleStrike().run();
          break;
        case "format-code":
          editor.chain().focus().toggleCode().run();
          break;
        case "format-heading-1":
          editor.chain().focus().toggleHeading({ level: 1 }).run();
          break;
        case "format-heading-2":
          editor.chain().focus().toggleHeading({ level: 2 }).run();
          break;
        case "format-heading-3":
          editor.chain().focus().toggleHeading({ level: 3 }).run();
          break;
        case "format-blockquote":
          editor.chain().focus().toggleBlockquote().run();
          break;
        case "format-bullet-list":
          editor.chain().focus().toggleBulletList().run();
          break;
        case "format-ordered-list":
          editor.chain().focus().toggleOrderedList().run();
          break;
        case "insert-link": {
          const href = editor.getAttributes("link").href ?? "";
          setLinkDialog({ href });
          break;
        }
        case "insert-code-block":
          editor.chain().focus().toggleCodeBlock().run();
          break;
        case "insert-hr":
          editor.chain().focus().setHorizontalRule().run();
          break;
        case "insert-table":
          editor.chain().focus().insertTable({ rows: 3, cols: 3, withHeaderRow: true }).run();
          break;
      }
    }).then((fn) => {
      if (mounted) {
        unlisten = fn;
      } else {
        fn();
      }
    });
    return () => {
      mounted = false;
      unlisten?.();
    };
  }, [editor, linkDialog]);

  return (
    <div className="editor-wrapper">
      <div ref={scrollRef} className="editor-scroll">
        <EditorContent editor={editor} />
      </div>
      {editor && showFindReplace && (
        <FindReplaceBar editor={editor} onClose={() => setShowFindReplace(false)} />
      )}
      {editor && <TableControls editor={editor} />}
      {editor && (
        <BubbleMenu
          editor={editor}
          onLinkClick={() => {
            const href = editor.getAttributes("link").href ?? "";
            setLinkDialog({ href });
          }}
        />
      )}
      {linkDialog && (
        <LinkDialog
          initialHref={linkDialog.href}
          onApply={(url) => {
            editor?.chain().focus().extendMarkRange("link").setLink({ href: url }).run();
            setLinkDialog(null);
          }}
          onRemove={() => {
            editor?.chain().focus().extendMarkRange("link").unsetLink().run();
            setLinkDialog(null);
          }}
          onCancel={() => setLinkDialog(null)}
        />
      )}
    </div>
  );
}

import type { Editor } from "@tiptap/react";
import { useEditorState } from "@tiptap/react";
import { FloatingMenu } from "@tiptap/react/menus";
import "./TableControls.css";

interface TableControlsProps {
  editor: Editor;
}

export function TableControls({ editor }: TableControlsProps) {
  const isInTable = useEditorState({
    editor,
    selector: ({ editor: e }) => e.isActive("table"),
  });

  return (
    <FloatingMenu
      editor={editor}
      shouldShow={() => isInTable}
    >
      <div className="table-controls" role="toolbar" aria-label="Table controls">
        <button
          type="button"
          className="table-ctrl-btn"
          title="Add row below"
          aria-label="Add row below"
          onMouseDown={(e) => {
            e.preventDefault();
            editor.chain().focus().addRowAfter().run();
          }}
        >
          +row
        </button>
        <button
          type="button"
          className="table-ctrl-btn"
          title="Delete row"
          aria-label="Delete row"
          onMouseDown={(e) => {
            e.preventDefault();
            editor.chain().focus().deleteRow().run();
          }}
        >
          −row
        </button>
        <div className="table-ctrl-divider" aria-hidden="true" />
        <button
          type="button"
          className="table-ctrl-btn"
          title="Add column after"
          aria-label="Add column after"
          onMouseDown={(e) => {
            e.preventDefault();
            editor.chain().focus().addColumnAfter().run();
          }}
        >
          +col
        </button>
        <button
          type="button"
          className="table-ctrl-btn"
          title="Delete column"
          aria-label="Delete column"
          onMouseDown={(e) => {
            e.preventDefault();
            editor.chain().focus().deleteColumn().run();
          }}
        >
          −col
        </button>
        <div className="table-ctrl-divider" aria-hidden="true" />
        <button
          type="button"
          className="table-ctrl-btn table-ctrl-delete"
          title="Delete table"
          aria-label="Delete table"
          onMouseDown={(e) => {
            e.preventDefault();
            editor.chain().focus().deleteTable().run();
          }}
        >
          ✕ table
        </button>
      </div>
    </FloatingMenu>
  );
}

