    expect(ranges).toHaveLength(2);
    expect(ranges[0].level).toBe(1);
    expect(ranges[1].level).toBe(1);
    // First H1 ends before Second H1
    expect(ranges[0].contentTo).toBeLessThan(ranges[1].headingFrom);
  });

