@import "tailwindcss";

/* Dark mode via data-theme="dark" attribute */
@custom-variant dark (&:where([data-theme="dark"], [data-theme="dark"] *));

/* ── Design tokens ─────────────────────────────────────────────────────────
   Single source of truth. Tailwind generates both CSS variables and
   utility classes from @theme (e.g. bg-surface, text-fg, border-border).
