.table-controls {
  display: flex;
  align-items: center;
  gap: 2px;
  padding: 4px 6px;
  background: var(--color-surface);
  border: 1px solid var(--color-border-strong);
  border-radius: 8px;
  box-shadow:
    0 4px 16px rgba(0, 0, 0, 0.12),
    0 1px 4px rgba(0, 0, 0, 0.08);
}

.table-ctrl-btn {
  height: 24px;
  padding: 0 7px;
  border: none;
  border-radius: 4px;
  background: transparent;
  color: var(--color-fg-muted);
  cursor: pointer;
  font-size: 11px;
  font-family: var(--font-mono);
  white-space: nowrap;
  transition:
    background 0.12s,
    color 0.12s;
}

.table-ctrl-btn:hover {
  background: var(--color-surface-hover);
  color: var(--color-fg);
}

.table-ctrl-delete {
  color: var(--color-fg-subtle);
}

.table-ctrl-delete:hover {
  background: color-mix(in srgb, red 10%, var(--color-surface-hover));
  color: red;
}

.table-ctrl-divider {
  width: 1px;
  height: 14px;
  background: var(--color-border);
  margin: 0 2px;
  flex-shrink: 0;
}

