@import "tailwindcss";

/* Dark mode via data-theme="dark" attribute */
@custom-variant dark (&:where([data-theme="dark"], [data-theme="dark"] *));

/* ── Design tokens ─────────────────────────────────────────────────────────
   Single source of truth. Tailwind generates both CSS variables and
   utility classes from @theme (e.g. bg-surface, text-fg, border-border).
   ───────────────────────────────────────────────────────────────────────── */
@theme {
  /* Surfaces */
  --color-surface: #fafafa;
  --color-surface-subtle: #f4f4f5;
  --color-surface-hover: #ebebec;
  --color-surface-active: #e4e4e7;

  /* Borders */
  --color-border: #e4e4e7;
  --color-border-strong: #d4d4d8;

  /* Foreground */
  --color-fg: #18181b;
  --color-fg-muted: #71717a;
  --color-fg-subtle: #a1a1aa;

  /* Accent (brand) */
  --color-accent: #6366f1;
  --color-accent-subtle: rgba(99, 102, 241, 0.12);

  /* Status */
  --color-warning: #f59e0b;
  --color-warning-subtle: rgba(245, 158, 11, 0.12);
  --color-success: #22c55e;
  --color-error: #c0392b;
  --color-danger: #e53e3e;

  /* Syntax highlighting */
  --color-syntax-comment: #a1a1aa;
  --color-syntax-keyword: #6366f1;
  --color-syntax-string: #16a34a;
  --color-syntax-meta: #d97706;
  --color-syntax-attr: #7c3aed;
  --color-syntax-number: #ea580c;

  /* Fonts */
  --font-ui: system-ui, -apple-system, sans-serif;
  --font-editor: "Georgia", "Times New Roman", serif;
  --font-mono: "Fira Code", "JetBrains Mono", monospace;
}

/* ── Dark mode overrides ──────────────────────────────────────────────────── */
[data-theme="dark"] {
  --color-surface: #1c1c1e;
  --color-surface-subtle: #161618;
  --color-surface-hover: #2c2c2e;
  --color-surface-active: #3a3a3c;

  --color-border: #3a3a3c;
  --color-border-strong: #48484a;

  --color-fg: #f2f2f7;
  --color-fg-muted: #aeaeb2;
  --color-fg-subtle: #636366;

  --color-accent: #7c7fff;
  --color-accent-subtle: rgba(124, 127, 255, 0.15);

  --color-warning: #fbbf24;
  --color-warning-subtle: rgba(251, 191, 36, 0.15);
  --color-success: #4ade80;

  --color-syntax-comment: #636366;
  --color-syntax-keyword: #a5b4fc;
  --color-syntax-string: #86efac;
  --color-syntax-meta: #fcd34d;
  --color-syntax-attr: #a78bfa;
  --color-syntax-number: #fb923c;
}

/* ── Constants (not in @theme — would conflict with Tailwind defaults) ──── */
:root {
  --font-editor-size: 17px;

  /* App-specific font size scale */
  --text-2xs: 10px;
  --text-xs: 11px;
  --text-sm: 12px;
  --text-base: 13px;
  --text-md: 13.5px;

  /* Layout */
  --sidebar-width: 240px;
  --statusbar-height: 28px;

  /* Shadows */
  --shadow-tooltip: rgba(0, 0, 0, 0.12);

  font-family: var(--font-ui);
  font-size: 14px;
  color: var(--color-fg);
  background: var(--color-surface);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  transition:
    background-color 0.2s ease,
    color 0.2s ease;
}

[data-theme="dark"] {
  --shadow-tooltip: rgba(0, 0, 0, 0.28);
}

@media (prefers-reduced-motion: reduce) {
  :root {
    transition: none;
  }
}

/* ── Reset ────────────────────────────────────────────────────────────────── */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html,
body,
#root {
  height: 100%;
  width: 100%;
  overflow: hidden;
}

button {
  font-family: var(--font-ui);
  cursor: pointer;
  border: none;
