        <FindReplaceBar editor={editor} onClose={() => setShowFindReplace(false)} />
      )}
      {editor && <TableControls editor={editor} />}
      {editor && (
        <BubbleMenu
          editor={editor}
          onLinkClick={() => {
            const href = editor.getAttributes("link").href ?? "";
            setLinkDialog({ href });
          }}
        />
      )}
